// Lexware vouchers from API
const lexwareRaw = $('📥 Fetch Lexware Vouchers').first().json;
const lexwareVouchers = lexwareRaw.content || lexwareRaw.results || lexwareRaw || [];

// DB invoices
const dbInvoices = $('📥 Fetch DB Invoices').all().map(i => i.json);

// Build lookup maps
const lexwareByNumber = {};
const lexwareById = {};
for (const v of (Array.isArray(lexwareVouchers) ? lexwareVouchers : [])) {
  const num = v.voucherNumber || v.invoiceNumber || '';
  if (num) lexwareByNumber[num] = v;
  if (v.id) lexwareById[v.id] = v;
}

const dbByNumber = {};
const dbByLexwareId = {};
for (const inv of dbInvoices) {
  if (inv.invoice_number) dbByNumber[inv.invoice_number] = inv;
  if (inv.lexware_voucher_id) dbByLexwareId[inv.lexware_voucher_id] = inv;
}

const results = {
  synced: [],        // a) In beiden — Status/Payment sync
  missing_lexware: [], // b) In DB aber NICHT in Lexware → nochmal senden
  lexware_only: [],  // c) In Lexware aber NICHT in DB → Info loggen
  errors: [],
  total_lexware: Array.isArray(lexwareVouchers) ? lexwareVouchers.length : 0,
  total_db: dbInvoices.length
};

// a) Match and sync: Lexware wins
for (const inv of dbInvoices) {
  let lexwareMatch = null;

  // Match by lexware_voucher_id first
  if (inv.lexware_voucher_id && lexwareById[inv.lexware_voucher_id]) {
    lexwareMatch = lexwareById[inv.lexware_voucher_id];
  }
  // Then by invoice_number
  else if (inv.invoice_number && lexwareByNumber[inv.invoice_number]) {
    lexwareMatch = lexwareByNumber[inv.invoice_number];
  }

  if (lexwareMatch) {
    const lexStatus = lexwareMatch.voucherStatus || lexwareMatch.status || '';
    const lexPaidAmount = lexwareMatch.paidAmount || lexwareMatch.totalGrossAmount || 0;
    const lexDueDate = lexwareMatch.dueDate || '';

    // Map Lexware status to our status
    let newStatus = inv.status;
    if (lexStatus === 'paid') newStatus = 'PAID';
    else if (lexStatus === 'overdue') newStatus = 'OVERDUE';
    else if (lexStatus === 'open') newStatus = 'APPROVED';

    const needsUpdate = (newStatus !== inv.status) ||
                        (lexPaidAmount !== inv.paid_amount);

    if (needsUpdate) {
      results.synced.push({
        db_id: inv.id,
        invoice_number: inv.invoice_number,
        old_status: inv.status,
        new_status: newStatus,
        paid_amount: lexPaidAmount,
        due_date: lexDueDate,
        lexware_id: lexwareMatch.id || ''
      });
    }
  } else {
    // b) In DB but not in Lexware
    if (inv.invoice_type !== 'credit_note') { // Don't resend credit notes
      results.missing_lexware.push({
        db_id: inv.id,
        invoice_number: inv.invoice_number,
        total_gross: inv.total_gross,
        pdf_storage_path: inv.pdf_storage_path,
        email_from: inv.email_from,
        lexware_forwarded_at: inv.lexware_forwarded_at
      });
    }
  }
}

// c) In Lexware but not in DB
for (const v of (Array.isArray(lexwareVouchers) ? lexwareVouchers : [])) {
  const num = v.voucherNumber || v.invoiceNumber || '';
  const id = v.id || '';
  if (num && !dbByNumber[num] && !dbByLexwareId[id]) {
    results.lexware_only.push({
      lexware_id: id,
      voucher_number: num,
      amount: v.totalGrossAmount || v.totalAmount || 0,
      status: v.voucherStatus || ''
    });
  }
}

return { json: results };

const reconcileData = $('🔄 Reconcile').first().json;
const synced = reconcileData.synced || [];

if (synced.length === 0) {
  return { json: { query: 'SELECT 1 -- nothing to sync', count: 0 } };
}

const updates = synced.map(s => {
  const status = s.new_status.replace(/'/g, "''");
  const lexId = (s.lexware_id || '').replace(/'/g, "''");
  return `UPDATE purchase_invoices SET status = '${status}'::purchase_invoice_status, paid_amount = ${s.paid_amount}, lexware_voucher_id = NULLIF('${lexId}', ''), lexware_synced_at = now(), updated_at = now() WHERE id = '${s.db_id}'::uuid;`;
}).join('\n');

return { json: { query: updates, count: synced.length } };

const reconcileData = $('🔄 Reconcile').first().json;
const missing = (reconcileData.missing_lexware || [])
  .filter(m => !m.lexware_forwarded_at && m.pdf_storage_path);

if (missing.length === 0) {
  return [{ json: { action: 'none', message: 'Keine fehlenden Belege zum Nachsenden' } }];
}

// Maximal 5 pro Tag resenden um Spam zu vermeiden
const toResend = missing.slice(0, 5);

// Logge nur — das eigentliche Senden macht M6_01 beim nächsten Durchlauf
return toResend.map(m => ({
  json: {
    action: 'flag_for_resend',
    db_id: m.db_id,
    invoice_number: m.invoice_number,
    total_gross: m.total_gross,
    pdf_storage_path: m.pdf_storage_path,
    email_from: m.email_from
  }
}));

